import{c as a,S as n,j as p,m as l}from"./chunks/framework.Bcm8lc2D.js";const d=JSON.parse('{"title":"Prompt工程实战：开发者写好提示词的方法与模板","description":"","frontmatter":{"title":"Prompt工程实战：开发者写好提示词的方法与模板","date":"2026-05-25T00:00:00.000Z","tags":"AI, AI工具, Prompt工程, 提示词","summary":"角色设定、Few-shot、Chain of Thought等Prompt技巧在开发场景的实战应用","author":"ai-helper"},"headers":[],"relativePath":"blog/posts/2026-05-25-Prompt工程实战写好提示词的方法.md","filePath":"blog/posts/2026-05-25-Prompt工程实战写好提示词的方法.md"}'),e={name:"blog/posts/2026-05-25-Prompt工程实战写好提示词的方法.md"};function i(t,s,o,c,r,h){return n(),p("div",null,s[0]||(s[0]=[l(`<h2 id="场景引入" tabindex="-1">场景引入 <a class="header-anchor" href="#场景引入" aria-label="Permalink to &quot;场景引入&quot;">​</a></h2><p>同一个需求，给AI写一句话和写一段结构化Prompt，输出质量天差地别。我见过同事让AI&quot;写一个用户注册接口&quot;，得到的是最简单的Controller加Service；而我用结构化Prompt，得到的是完整的参数校验、异常处理、密码加密、邮箱验证的完整方案。</p><p>Prompt工程不是玄学，是有方法论的。这篇文章分享我在实际开发中验证有效的Prompt技巧和模板。</p><h2 id="核心技巧" tabindex="-1">核心技巧 <a class="header-anchor" href="#核心技巧" aria-label="Permalink to &quot;核心技巧&quot;">​</a></h2><h3 id="_1-角色设定-role-prompting" tabindex="-1">1. 角色设定（Role Prompting） <a class="header-anchor" href="#_1-角色设定-role-prompting" aria-label="Permalink to &quot;1. 角色设定（Role Prompting）&quot;">​</a></h3><p>给AI一个角色，它会调整输出的专业度和风格。</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span># 差的Prompt</span></span>
<span class="line"><span>写一个订单服务</span></span>
<span class="line"><span></span></span>
<span class="line"><span># 好的Prompt</span></span>
<span class="line"><span>你是一个有10年经验的Java后端工程师，擅长Spring Boot和DDD设计。</span></span>
<span class="line"><span>请为电商系统设计一个订单服务，要求：</span></span>
<span class="line"><span>- 遵循DDD的聚合根设计模式</span></span>
<span class="line"><span>- 考虑并发场景下的库存扣减</span></span>
<span class="line"><span>- 包含订单状态机管理</span></span></code></pre></div><p><strong>实测对比</strong>：角色设定后的输出，代码结构更专业，会主动考虑边界情况，而不是给你最简单的CRUD。</p><h3 id="_2-few-shot示例" tabindex="-1">2. Few-shot示例 <a class="header-anchor" href="#_2-few-shot示例" aria-label="Permalink to &quot;2. Few-shot示例&quot;">​</a></h3><p>给AI一两个&quot;输入-输出&quot;示例，它会模仿你的风格。</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>请按照以下格式为项目中的工具类编写Javadoc：</span></span>
<span class="line"><span></span></span>
<span class="line"><span>示例输入：</span></span>
<span class="line"><span>public class DateUtils {</span></span>
<span class="line"><span>    public static String formatDate(Date date, String pattern) { ... }</span></span>
<span class="line"><span>}</span></span>
<span class="line"><span></span></span>
<span class="line"><span>示例输出：</span></span>
<span class="line"><span>/**</span></span>
<span class="line"><span> * 日期工具类，提供常用的日期格式化和解析方法。</span></span>
<span class="line"><span> * &lt;p&gt;线程安全，所有方法均为静态方法。&lt;/p&gt;</span></span>
<span class="line"><span> * </span></span>
<span class="line"><span> * @author ai-helper</span></span>
<span class="line"><span> * @since 1.0.0</span></span>
<span class="line"><span> */</span></span>
<span class="line"><span>public class DateUtils {</span></span>
<span class="line"><span>    /**</span></span>
<span class="line"><span>     * 将日期对象格式化为指定格式的字符串。</span></span>
<span class="line"><span>     *</span></span>
<span class="line"><span>     * @param date 待格式化的日期对象，不能为null</span></span>
<span class="line"><span>     * @param pattern 格式化模式，如 &quot;yyyy-MM-dd HH:mm:ss&quot;</span></span>
<span class="line"><span>     * @return 格式化后的日期字符串</span></span>
<span class="line"><span>     * @throws IllegalArgumentException 当date或pattern为null时抛出</span></span>
<span class="line"><span>     */</span></span>
<span class="line"><span>    public static String formatDate(Date date, String pattern) { ... }</span></span>
<span class="line"><span>}</span></span>
<span class="line"><span></span></span>
<span class="line"><span>现在请为以下类编写Javadoc：</span></span>
<span class="line"><span>[粘贴代码]</span></span></code></pre></div><h3 id="_3-chain-of-thought-思维链" tabindex="-1">3. Chain of Thought（思维链） <a class="header-anchor" href="#_3-chain-of-thought-思维链" aria-label="Permalink to &quot;3. Chain of Thought（思维链）&quot;">​</a></h3><p>让AI&quot;一步步思考&quot;，复杂任务的准确率显著提升。</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>请分析以下慢查询SQL，按以下步骤思考：</span></span>
<span class="line"><span></span></span>
<span class="line"><span>1. 先解释这个SQL的业务意图</span></span>
<span class="line"><span>2. 分析执行计划，找出瓶颈</span></span>
<span class="line"><span>3. 检查是否有索引可以优化</span></span>
<span class="line"><span>4. 给出优化建议（包括改写SQL和添加索引）</span></span>
<span class="line"><span>5. 评估优化后的预期性能提升</span></span>
<span class="line"><span></span></span>
<span class="line"><span>SQL: </span></span>
<span class="line"><span>SELECT o.*, u.name, u.phone </span></span>
<span class="line"><span>FROM orders o </span></span>
<span class="line"><span>LEFT JOIN users u ON o.user_id = u.id </span></span>
<span class="line"><span>WHERE o.create_time &gt; &#39;2026-01-01&#39; </span></span>
<span class="line"><span>AND o.status IN (1, 2, 3)</span></span>
<span class="line"><span>ORDER BY o.create_time DESC </span></span>
<span class="line"><span>LIMIT 10000, 20;</span></span></code></pre></div><p>这种方式让AI不会&quot;跳步&quot;，输出更有逻辑性。</p><h3 id="_4-结构化输出" tabindex="-1">4. 结构化输出 <a class="header-anchor" href="#_4-结构化输出" aria-label="Permalink to &quot;4. 结构化输出&quot;">​</a></h3><p>明确要求输出格式，减少后续整理工作。</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>请审查这段代码，以JSON格式输出结果：</span></span>
<span class="line"><span></span></span>
<span class="line"><span>{</span></span>
<span class="line"><span>  &quot;issues&quot;: [</span></span>
<span class="line"><span>    {</span></span>
<span class="line"><span>      &quot;file&quot;: &quot;文件名&quot;,</span></span>
<span class="line"><span>      &quot;line&quot;: 行号,</span></span>
<span class="line"><span>      &quot;severity&quot;: &quot;high|medium|low&quot;,</span></span>
<span class="line"><span>      &quot;category&quot;: &quot;security|performance|readability|bug&quot;,</span></span>
<span class="line"><span>      &quot;description&quot;: &quot;问题描述&quot;,</span></span>
<span class="line"><span>      &quot;suggestion&quot;: &quot;修改建议&quot;,</span></span>
<span class="line"><span>      &quot;code_example&quot;: &quot;示例代码&quot;</span></span>
<span class="line"><span>    }</span></span>
<span class="line"><span>  ],</span></span>
<span class="line"><span>  &quot;summary&quot;: {</span></span>
<span class="line"><span>    &quot;total&quot;: 数量,</span></span>
<span class="line"><span>    &quot;high&quot;: 数量,</span></span>
<span class="line"><span>    &quot;medium&quot;: 数量,</span></span>
<span class="line"><span>    &quot;low&quot;: 数量,</span></span>
<span class="line"><span>    &quot;overall_quality&quot;: &quot;1-10分评分&quot;</span></span>
<span class="line"><span>  }</span></span>
<span class="line"><span>}</span></span></code></pre></div><h3 id="_5-约束条件" tabindex="-1">5. 约束条件 <a class="header-anchor" href="#_5-约束条件" aria-label="Permalink to &quot;5. 约束条件&quot;">​</a></h3><p>明确告诉AI&quot;不要做什么&quot;，和&quot;要做什么&quot;同样重要。</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>请重构这个Service类，要求：</span></span>
<span class="line"><span></span></span>
<span class="line"><span>必须：</span></span>
<span class="line"><span>- 保持所有public方法签名不变（外部有调用）</span></span>
<span class="line"><span>- 使用Spring的构造器注入</span></span>
<span class="line"><span>- 保持@Transactional注解在正确的位置</span></span>
<span class="line"><span></span></span>
<span class="line"><span>禁止：</span></span>
<span class="line"><span>- 不要引入新的依赖</span></span>
<span class="line"><span>- 不要使用反射</span></span>
<span class="line"><span>- 不要修改数据库表结构</span></span>
<span class="line"><span>- 不要使用Java 8以上的特性（项目还在用JDK 8）</span></span></code></pre></div><h2 id="实战prompt模板库" tabindex="-1">实战Prompt模板库 <a class="header-anchor" href="#实战prompt模板库" aria-label="Permalink to &quot;实战Prompt模板库&quot;">​</a></h2><h3 id="模板1-生成api接口" tabindex="-1">模板1：生成API接口 <a class="header-anchor" href="#模板1-生成api接口" aria-label="Permalink to &quot;模板1：生成API接口&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>角色：Spring Boot后端工程师</span></span>
<span class="line"><span>任务：生成 [功能名称] 的REST API</span></span>
<span class="line"><span></span></span>
<span class="line"><span>技术栈：</span></span>
<span class="line"><span>- Spring Boot 3.2 + MyBatis-Plus</span></span>
<span class="line"><span>- 数据库：MySQL 8.0</span></span>
<span class="line"><span>- 参数校验：@Valid + 自定义注解</span></span>
<span class="line"><span>- 统一响应：Result&lt;T&gt; 包装类</span></span>
<span class="line"><span>- 异常处理：@RestControllerAdvice</span></span>
<span class="line"><span></span></span>
<span class="line"><span>要求：</span></span>
<span class="line"><span>1. Controller层：RESTful风格，包含Swagger注解</span></span>
<span class="line"><span>2. Service层：业务逻辑，事务管理</span></span>
<span class="line"><span>3. DTO层：请求/响应对象，包含校验注解</span></span>
<span class="line"><span>4. 参数校验：非空、长度、格式等</span></span>
<span class="line"><span>5. 异常处理：业务异常和系统异常分别处理</span></span>
<span class="line"><span></span></span>
<span class="line"><span>接口详情：</span></span>
<span class="line"><span>- 路径：POST /api/v1/[资源]</span></span>
<span class="line"><span>- 请求参数：[列出字段和类型]</span></span>
<span class="line"><span>- 业务规则：[描述业务逻辑]</span></span>
<span class="line"><span>- 响应格式：{code, message, data}</span></span></code></pre></div><h3 id="模板2-生成单元测试" tabindex="-1">模板2：生成单元测试 <a class="header-anchor" href="#模板2-生成单元测试" aria-label="Permalink to &quot;模板2：生成单元测试&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>角色：测试工程师</span></span>
<span class="line"><span>任务：为以下类编写单元测试</span></span>
<span class="line"><span></span></span>
<span class="line"><span>要求：</span></span>
<span class="line"><span>- 框架：JUnit 5 + Mockito</span></span>
<span class="line"><span>- 覆盖率目标：行覆盖80%+</span></span>
<span class="line"><span>- 测试场景：</span></span>
<span class="line"><span>  1. 正常流程</span></span>
<span class="line"><span>  2. 边界条件（null、空集合、0值）</span></span>
<span class="line"><span>  3. 异常场景（业务异常、系统异常）</span></span>
<span class="line"><span>- Mock策略：只Mock外部依赖（数据库、远程调用）</span></span>
<span class="line"><span>- 命名规范：方法名_场景_期望结果</span></span>
<span class="line"><span></span></span>
<span class="line"><span>请按Given-When-Then格式组织每个测试方法。</span></span></code></pre></div><h3 id="模板3-代码解释" tabindex="-1">模板3：代码解释 <a class="header-anchor" href="#模板3-代码解释" aria-label="Permalink to &quot;模板3：代码解释&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>请解释以下代码，要求：</span></span>
<span class="line"><span></span></span>
<span class="line"><span>1. 总体功能：一句话说明这段代码做什么</span></span>
<span class="line"><span>2. 逐行解释：对关键行添加注释</span></span>
<span class="line"><span>3. 设计模式：是否使用了设计模式，为什么</span></span>
<span class="line"><span>4. 潜在问题：有没有bug、性能问题、安全风险</span></span>
<span class="line"><span>5. 改进建议：如果有，给出更好的写法</span></span>
<span class="line"><span></span></span>
<span class="line"><span>[粘贴代码]</span></span></code></pre></div><h3 id="模板4-sql优化" tabindex="-1">模板4：SQL优化 <a class="header-anchor" href="#模板4-sql优化" aria-label="Permalink to &quot;模板4：SQL优化&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>角色：数据库优化专家</span></span>
<span class="line"><span>任务：优化以下SQL</span></span>
<span class="line"><span></span></span>
<span class="line"><span>环境信息：</span></span>
<span class="line"><span>- 数据库：MySQL 8.0</span></span>
<span class="line"><span>- 表数据量：[表名]约[X]万行</span></span>
<span class="line"><span>- 当前索引：[列出索引]</span></span>
<span class="line"><span>- 慢查询阈值：200ms</span></span>
<span class="line"><span></span></span>
<span class="line"><span>请分析：</span></span>
<span class="line"><span>1. 当前SQL的执行计划</span></span>
<span class="line"><span>2. 瓶颈在哪里</span></span>
<span class="line"><span>3. 给出至少2种优化方案</span></span>
<span class="line"><span>4. 每种方案的优缺点</span></span>
<span class="line"><span>5. 推荐方案及理由</span></span>
<span class="line"><span></span></span>
<span class="line"><span>[粘贴SQL]</span></span></code></pre></div><h2 id="prompt调优经验" tabindex="-1">Prompt调优经验 <a class="header-anchor" href="#prompt调优经验" aria-label="Permalink to &quot;Prompt调优经验&quot;">​</a></h2><h3 id="_1-迭代式优化" tabindex="-1">1. 迭代式优化 <a class="header-anchor" href="#_1-迭代式优化" aria-label="Permalink to &quot;1. 迭代式优化&quot;">​</a></h3><p>不要期望一次写出完美Prompt。我的工作流是：</p><ol><li>写一个基础版本</li><li>看AI的输出，找到不满意的地方</li><li>在Prompt中添加针对性的约束</li><li>重复2-3次，通常能得到满意结果</li></ol><h3 id="_2-prompt版本管理" tabindex="-1">2. Prompt版本管理 <a class="header-anchor" href="#_2-prompt版本管理" aria-label="Permalink to &quot;2. Prompt版本管理&quot;">​</a></h3><p>好用的Prompt保存下来，我们团队建了一个共享的Prompt库：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/prompts</span></span>
<span class="line"><span>  /java</span></span>
<span class="line"><span>    api-generator.md</span></span>
<span class="line"><span>    unit-test.md</span></span>
<span class="line"><span>    code-review.md</span></span>
<span class="line"><span>  /sql</span></span>
<span class="line"><span>    slow-query-optimizer.md</span></span>
<span class="line"><span>    schema-design.md</span></span>
<span class="line"><span>  /docs</span></span>
<span class="line"><span>    javadoc-generator.md</span></span>
<span class="line"><span>    changelog.md</span></span></code></pre></div><h3 id="_3-不要过度复杂" tabindex="-1">3. 不要过度复杂 <a class="header-anchor" href="#_3-不要过度复杂" aria-label="Permalink to &quot;3. 不要过度复杂&quot;">​</a></h3><p>简单任务不需要复杂Prompt。写一个工具方法，一句&quot;用Java写一个字符串脱敏方法&quot;就够了。过度工程化的Prompt反而会让AI&quot;过度思考&quot;，输出啰嗦的代码。</p><h2 id="总结" tabindex="-1">总结 <a class="header-anchor" href="#总结" aria-label="Permalink to &quot;总结&quot;">​</a></h2><p>Prompt工程的本质是<strong>清晰地表达你的需求</strong>。你越清楚自己要什么，AI给你的就越接近你要的。</p><p>核心原则：</p><ol><li><strong>给角色</strong>：让AI进入正确的&quot;人设&quot;</li><li><strong>给示例</strong>：一图胜千言，一例胜万句</li><li><strong>给约束</strong>：明确边界比明确方向更重要</li><li><strong>要结构化输出</strong>：省去后续整理的时间</li><li><strong>迭代优化</strong>：好Prompt是调出来的，不是一次写出来的</li></ol><hr><p><em>Prompt技巧在不同AI模型间有差异，本文示例基于GPT-4和Claude测试，其他模型可能需要微调。</em></p>`,45)]))}const m=a(e,[["render",i]]);export{d as __pageData,m as default};
